const readline = require('readline');

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

let input = [];
rl.on('line', (line) => {
  input.push(line.trim());
});

rl.on('close', () => {
  let n = parseInt(input[0]);
  let matrix = [];

  for (let i = 1; i <= n; i++) {
    matrix.push(input[i].split(' ').map(Number));
  }

  let sum = 0;
  for (let i = 0; i < n; i++) {
    sum += matrix[i][i];             // Primary diagonal
    if (i !== n - 1 - i) {
      sum += matrix[i][n - 1 - i];    // Secondary diagonal, avoiding double-counting the center element in odd-sized matrices
    }
  }

  console.log(sum);
});
